package com.ichi2.anki

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.tests.InMemoryDatabase
import com.ichi2.testutils.createTransientDirectory
import kotlinx.coroutines.runBlocking
import org.json.JSONArray
import org.json.JSONObject
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import kotlin.test.assertEquals
import kotlin.test.assertTrue

@RunWith(AndroidJUnit4::class)
class AnkiDroidJsAPITagsTest : InMemoryDatabase() {
    private lateinit var jsApi: TestAnkiDroidJsAPI
    private var noteId: Long = 0

    @Before
    fun setUp() {
        jsApi = TestAnkiDroidJsAPI()
        // Create a test note
        val note = col.newNote()
        note.setField(0, "Test Front")
        note.setField(1, "Test Back")
        note.addTag("tag1")
        note.addTag("tag2")
        col.addNote(note)
        noteId = note.id
    }

    @Test
    fun testGetTagsFromNote() =
        runBlocking {
            val request = createApiRequest("getTagsFromNote", JSONObject().apply { put("noteId", noteId) }.toString())
            val response = jsApi.handleJsApiRequest("getTagsFromNote", request, false)
            val result = JSONObject(response.decodeToString())

            assertTrue(result.getBoolean("success"))
            val tags = JSONArray(result.getString("value"))
            assertEquals(2, tags.length())
            assertTrue(tags.getString(0) == "tag1" || tags.getString(0) == "tag2")
            assertTrue(tags.getString(1) == "tag1" || tags.getString(1) == "tag2")
        }

    @Test
    fun testSetNoteTags() =
        runBlocking {
            val newTags = JSONArray().apply { put("newTag1"); put("newTag2"); put("newTag3") }
            val request =
                createApiRequest(
                    "setNoteTags",
                    JSONObject().apply {
                        put("noteId", noteId)
                        put("tags", newTags)
                    }.toString(),
                )
            val response = jsApi.handleJsApiRequest("setNoteTags", request, false)
            val result = JSONObject(response.decodeToString())

            assertTrue(result.getBoolean("success"))
            assertTrue(result.getBoolean("value"))

            // Verify tags were set
            val note = col.getNote(noteId)
            assertEquals(3, note.tags.size)
            assertTrue(note.tags.contains("newTag1"))
            assertTrue(note.tags.contains("newTag2"))
            assertTrue(note.tags.contains("newTag3"))
        }

    @Test
    fun testRemoveTagUsingSetNoteTags() =
        runBlocking {
            // First, get current tags
            val getRequest = createApiRequest("getTagsFromNote", JSONObject().apply { put("noteId", noteId) }.toString())
            val getResponse = jsApi.handleJsApiRequest("getTagsFromNote", getRequest, false)
            val getResult = JSONObject(getResponse.decodeToString())

            val currentTags = JSONArray(getResult.getString("value"))

            // Remove "tag1" by setting tags to only "tag2"
            val newTags = JSONArray().apply { put("tag2") }
            val setRequest =
                createApiRequest(
                    "setNoteTags",
                    JSONObject().apply {
                        put("noteId", noteId)
                        put("tags", newTags)
                    }.toString(),
                )
            val setResponse = jsApi.handleJsApiRequest("setNoteTags", setRequest, false)
            val setResult = JSONObject(setResponse.decodeToString())

            assertTrue(setResult.getBoolean("success"))

            // Verify tag was removed
            val note = col.getNote(noteId)
            assertEquals(1, note.tags.size)
            assertTrue(note.tags.contains("tag2"))
            assertTrue(!note.tags.contains("tag1"))
        }

    @Test
    fun testSetNoteTagsWithEmptyArray() =
        runBlocking {
            val newTags = JSONArray()
            val request =
                createApiRequest(
                    "setNoteTags",
                    JSONObject().apply {
                        put("noteId", noteId)
                        put("tags", newTags)
                    }.toString(),
                )
            val response = jsApi.handleJsApiRequest("setNoteTags", request, false)
            val result = JSONObject(response.decodeToString())

            assertTrue(result.getBoolean("success"))
            assertTrue(result.getBoolean("value"))

            // Verify all tags were removed
            val note = col.getNote(noteId)
            assertEquals(0, note.tags.size)
        }

    private fun createApiRequest(
        endpoint: String,
        data: String,
    ): ByteArray {
        val request =
            JSONObject().apply {
                put("version", "0.0.3")
                put("developer", "test@test.com")
                put("data", data)
            }
        return request.toString().toByteArray()
    }

    private inner class TestAnkiDroidJsAPI : AnkiDroidJsAPI(
        object : AbstractFlashcardViewer() {
            override fun getColUnsafe() = this@AnkiDroidJsAPITagsTest.col
        },
    )
}
"}

